package com.example.userapp.ui;

import android.os.Bundle;
import android.view.View;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.userapp.R;
import com.example.userapp.network.NetworkConfig;
import com.example.userapp.ui.adapter.UserAdapter;
import com.example.userapp.viewmodel.UserViewModel;

public class MainActivity extends AppCompatActivity {

    private UserViewModel userViewModel;
    private UserAdapter userAdapter;
    private RecyclerView recyclerView;
    private ProgressBar progressBar;
    private TextView tvError;
    private TextView tvEnvBanner;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        initViews();
        setupEnvironmentBanner();
        setupRecyclerView();
        setupViewModel();

        userViewModel.loadUsers();
    }

    private void initViews() {
        recyclerView = findViewById(R.id.recycler_view_users);
        progressBar = findViewById(R.id.progress_bar);
        tvError = findViewById(R.id.tv_error);
        tvEnvBanner = findViewById(R.id.tv_env_banner);
    }

    private void setupEnvironmentBanner() {
        if (NetworkConfig.isDebugEnvironment()) {
            tvEnvBanner.setVisibility(View.VISIBLE);
            tvEnvBanner.setText("ENV: " + NetworkConfig.ENV_NAME.toUpperCase() + " | " + NetworkConfig.BASE_URL);
        } else {
            tvEnvBanner.setVisibility(View.GONE);
        }
    }

    private void setupRecyclerView() {
        userAdapter = new UserAdapter();
        recyclerView.setLayoutManager(new LinearLayoutManager(this));
        recyclerView.setAdapter(userAdapter);

        userAdapter.setOnUserClickListener(user -> {
            Toast.makeText(this, "Selected: " + user.getName(), Toast.LENGTH_SHORT).show();
        });
    }

    private void setupViewModel() {
        userViewModel = new ViewModelProvider(this).get(UserViewModel.class);

        userViewModel.getUsers().observe(this, users -> {
            if (users != null && !users.isEmpty()) {
                recyclerView.setVisibility(View.VISIBLE);
                tvError.setVisibility(View.GONE);
                userAdapter.setUsers(users);
            } else {
                recyclerView.setVisibility(View.GONE);
                tvError.setVisibility(View.VISIBLE);
                tvError.setText("No users found.");
            }
        });

        userViewModel.isLoading().observe(this, isLoading -> {
            progressBar.setVisibility(isLoading ? View.VISIBLE : View.GONE);
        });

        userViewModel.getError().observe(this, error -> {
            if (error != null && !error.isEmpty()) {
                tvError.setVisibility(View.VISIBLE);
                tvError.setText(error);
                recyclerView.setVisibility(View.GONE);
            }
        });
    }
}

